#!/usr/bin/env node
/**
 * Merges media-manifest.json (podcast + video explainer metadata, generated by
 * generate-media-manifest.py) into chaptersData.js, adding/refreshing the
 * `podcast` and `explainer` fields on whichever chapters currently have media.
 * Chapters without media simply keep no podcast/explainer field at all --
 * the site's UI already checks for that and hides Listen/Watch accordingly.
 *
 * This script is idempotent: re-running it after adding more chapter media
 * just updates the affected chapters and leaves everything else untouched.
 *
 * Usage (run from the taoist_sanctuary_deploy/ folder):
 *     node scripts/merge-media-manifest.js
 *
 * Reads:  ./chaptersData.js, ./media-manifest.json
 * Writes: ./chaptersData.js (in place)
 *
 * IMPORTANT: chaptersData.js in this folder is the canonical source of truth
 * for chapter content + media metadata. After running this script, the
 * website's actual app.js (deploy) and the single-file master HTML still need
 * to be reassembled from the updated chaptersData.js -- that reassembly step
 * currently happens during a Cowork/Claude session, since it also involves
 * the rest of the site's JS logic. Ask Claude to "rebuild the site from the
 * updated chaptersData.js" after running this script.
 */
const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const CHAPTERS_PATH = path.join(ROOT, 'chaptersData.js');
const MANIFEST_PATH = path.join(ROOT, 'media-manifest.json');

function jsLit(v) {
    return JSON.stringify(v);
}

function main() {
    if (!fs.existsSync(CHAPTERS_PATH)) {
        console.error(`ERROR: ${CHAPTERS_PATH} not found.`);
        process.exit(1);
    }
    if (!fs.existsSync(MANIFEST_PATH)) {
        console.error(`ERROR: ${MANIFEST_PATH} not found. Run generate-media-manifest.py first.`);
        process.exit(1);
    }

    const src = fs.readFileSync(CHAPTERS_PATH, 'utf-8');
    const manifest = JSON.parse(fs.readFileSync(MANIFEST_PATH, 'utf-8'));

    const chapters = new Function(src + '\nreturn chaptersData;')();

    let podcastCount = 0, explainerCount = 0;
    for (const ch of chapters) {
        const p = manifest.podcasts[String(ch.number)];
        const e = manifest.explainers[String(ch.number)];
        if (p) {
            ch.podcast = { title: p.title, key: p.r2Key, durationSeconds: p.durationSeconds };
            podcastCount++;
        } else {
            delete ch.podcast;
        }
        if (e) {
            ch.explainer = { title: e.title, key: e.r2Key, durationSeconds: e.durationSeconds };
            explainerCount++;
        } else {
            delete ch.explainer;
        }
    }

    let out = 'const chaptersData = [\n';
    chapters.forEach((ch, idx) => {
        out += '            {\n';
        out += '                number: ' + ch.number + ',\n';
        out += '                title: ' + jsLit(ch.title) + ',\n';
        out += '                chinese: ' + jsLit(ch.chinese) + ',\n';
        out += '                translation: ' + jsLit(ch.translation) + ',\n';
        out += '                theme: ' + jsLit(ch.theme) + ',\n';
        out += '                keyTakeaway: ' + jsLit(ch.keyTakeaway) + ',\n';
        out += '                article: ' + jsLit(ch.article);
        if (ch.podcast) {
            out += ',\n                podcast: { title: ' + jsLit(ch.podcast.title) + ', key: ' + jsLit(ch.podcast.key) + ', durationSeconds: ' + ch.podcast.durationSeconds + ' }';
        }
        if (ch.explainer) {
            out += ',\n                explainer: { title: ' + jsLit(ch.explainer.title) + ', key: ' + jsLit(ch.explainer.key) + ', durationSeconds: ' + ch.explainer.durationSeconds + ' }';
        }
        out += '\n            }' + (idx < chapters.length - 1 ? ',' : '') + '\n';
    });
    out += '        ];\n';

    fs.writeFileSync(CHAPTERS_PATH, out, 'utf-8');
    console.log(`Updated ${CHAPTERS_PATH}`);
    console.log(`chapters with podcast: ${podcastCount}, chapters with explainer: ${explainerCount}`);
}

main();
